"use client";

import { useCallback, useEffect, useState } from "react";

// shadcn
import { Button } from "@/components/ui/button";
import {
  Carousel,
  CarouselApi,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";

// project
import { cn } from "@/lib/utils";

// assets
import { Github, Globe, Linkedin } from "lucide-react";

// constants
const members = [
  {
    id: 1,
    name: "Alex Johnson",
    role: "Manager at Google",
    bio: "At half-past eight the door opened, the requesting them to follow him policeman appeared and requesting them to opened the policeman appeared and follow him.",
    image: "https://cdn.uiable.com/block/team1.png",
  },
  {
    id: 2,
    name: "Shirley Hoe",
    role: "Manager at Apple",
    bio: "At half-past eight the door opened, the requesting them to follow him policeman appeared and requesting them to opened the policeman appeared and follow him.",
    image: "https://cdn.uiable.com/block/team2.png",
  },
  {
    id: 3,
    name: "Maria Chen",
    role: "Designer at Meta",
    bio: "At half-past eight the door opened, the requesting them to follow him policeman appeared and requesting them to opened the policeman appeared and follow him.",
    image: "https://cdn.uiable.com/block/team3.png",
  },
  {
    id: 4,
    name: "James Park",
    role: "Senior Frontend Engineer",
    bio: "James is passionate about building performant, accessible web experiences. He leads the frontend architecture team and mentors junior developers across the organization.",
    image: "https://cdn.uiable.com/block/team4.png",
  },
];

//  ------------------------------ | TEAM 3 | ------------------------------  //

export default function Team3() {
  const [api, setApi] = useState<CarouselApi>();
  const [current, setCurrent] = useState(0);

  const wrap = (i: number) =>
    ((i % members.length) + members.length) % members.length;

  const onSelect = useCallback(() => {
    if (!api) return;
    setCurrent(api.selectedScrollSnap());
  }, [api]);

  useEffect(() => {
    if (!api) return;
    setTimeout(() => onSelect(), 0);
    api.on("select", onSelect);
    return () => {
      api.off("select", onSelect);
    };
  }, [api, onSelect]);

  // selectedScrollSnap() = left/start item; center item is always current+1
  const activeIndex = wrap(current + 1);
  const activeMember = members[activeIndex];

  return (
    <section className="py-20">
      <div className="mx-auto container px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14">
          <h2 className="text-foreground">Our Crew</h2>
          <p className="mt-4 max-w-xl mx-auto text-muted-foreground">
            At half-past eight the door opened, the policeman appeared and
            requesting them to follow him, led way to an adjoining hall.
          </p>
        </div>

        {/* Carousel — avatars only */}
        <Carousel
          setApi={setApi}
          opts={{ align: "start", loop: true }}
          className="w-full"
        >
          <CarouselContent className="-ml-4 items-center">
            {members.map((member, index) => {
              const isActive = index === activeIndex;
              return (
                <CarouselItem
                  key={member.id}
                  className="basis-1/3 pl-4 flex justify-center"
                >
                  <div
                    className={cn(
                      "rounded-full overflow-hidden transition-all duration-500",
                      isActive
                        ? "size-36 opacity-100"
                        : "size-20 opacity-50 grayscale",
                    )}
                  >
                    <img
                      src={member.image}
                      alt={member.name}
                      className="w-full h-full object-cover"
                    />
                  </div>
                </CarouselItem>
              );
            })}
          </CarouselContent>
          {/* Position arrows between side avatar and center avatar (at ~1/3 inward) */}
          <CarouselPrevious className="left-[calc(33%-1.5rem)]" />
          <CarouselNext className="right-[calc(33%-1.5rem)]" />
        </Carousel>

        {/* Info section — synced with active slide */}
        <div className="text-center mt-10">
          <h4 className="font-bold mb-1">{activeMember.name}</h4>
          <p className="text-muted-foreground mb-4">{activeMember.role}</p>
          <p className="text-muted-foreground max-w-md mx-auto mb-6">
            {activeMember.bio}
          </p>
          <div className="flex items-center justify-center gap-3">
            <Button
              variant="outline"
              size="icon"
              className="rounded-full"
              aria-label="Github"
            >
              <Github size={16} />
            </Button>
            <Button
              variant="outline"
              size="icon"
              className="rounded-full"
              aria-label="LinkedIn"
            >
              <Linkedin size={16} />
            </Button>
            <Button
              variant="outline"
              size="icon"
              className="rounded-full"
              aria-label="Website"
            >
              <Globe size={16} />
            </Button>
          </div>
        </div>
      </div>
    </section>
  );
}
